@if(prod)
package flux

prod: _base & {
	app:            "flux-prod"
	primary_region: "iad"
	custom_domains: ["flux.gunk.dev"]

	http_service: {
		auto_stop_machines:   "off"
		auto_start_machines:  true
		min_machines_running: 1
	}
}

@if(staging)
package flux

staging: _base & {
	app:            "flux-staging"
	primary_region: "iad"
	custom_domains: ["staging.flux.gunk.dev"]

	http_service: {
		auto_stop_machines:   "suspend"
		auto_start_machines:  true
		min_machines_running: 1
	}
}

@if(preview)
package flux

preview: _base & {
	app:            string | *"flux-preview" @tag(appName)
	primary_region: "iad"

	http_service: {
		auto_stop_machines:   "suspend"
		auto_start_machines:  true
		min_machines_running: 0
	}
}

